/**
 * CONTEXT Command
 *
 * Get LLM-ready summary of markdown files.
 */

import * as path from 'node:path'
import { Args, Command, Options } from '@effect/cli'
import { Console, Effect } from 'effect'
import {
  assembleContext,
  formatAssembledContext,
  formatSummary,
  summarizeFile,
} from '../../summarize/summarizer.js'
import { jsonOption, prettyOption } from '../options.js'
import { formatJson } from '../utils.js'

export const contextCommand = Command.make(
  'context',
  {
    files: Args.file({ name: 'files' }).pipe(
      Args.withDescription('Markdown file(s) to summarize'),
      Args.repeated,
    ),
    tokens: Options.integer('tokens').pipe(
      Options.withAlias('t'),
      Options.withDescription('Token budget'),
      Options.withDefault(2000),
    ),
    brief: Options.boolean('brief').pipe(
      Options.withDescription('Minimal output'),
      Options.withDefault(false),
    ),
    full: Options.boolean('full').pipe(
      Options.withDescription('Include full content'),
      Options.withDefault(false),
    ),
    json: jsonOption,
    pretty: prettyOption,
  },
  ({ files, tokens, brief, full, json, pretty }) =>
    Effect.gen(function* () {
      // Effect CLI Args.repeated returns an array
      const fileList: string[] = Array.isArray(files) ? files : []

      if (fileList.length === 0) {
        yield* Effect.fail(
          new Error(
            'At least one file is required. Usage: mdtldr context <file> [files...]',
          ),
        )
      }

      // Determine level
      const level = full ? 'full' : brief ? 'brief' : 'summary'

      const firstFile = fileList[0]
      if (fileList.length === 1 && firstFile) {
        // Single file: use summarizeFile
        const filePath = path.resolve(firstFile)
        const summary = yield* summarizeFile(filePath, {
          level: level as 'brief' | 'summary' | 'full',
          maxTokens: tokens,
        })

        if (json) {
          yield* Console.log(formatJson(summary, pretty))
        } else {
          yield* Console.log(formatSummary(summary, { maxTokens: tokens }))
        }
      } else {
        // Multiple files: use assembleContext
        const root = process.cwd()
        const assembled = yield* assembleContext(root, fileList, {
          budget: tokens,
          level: level as 'brief' | 'summary' | 'full',
        })

        if (json) {
          yield* Console.log(formatJson(assembled, pretty))
        } else {
          yield* Console.log(formatAssembledContext(assembled))
        }
      }
    }),
).pipe(Command.withDescription('Get LLM-ready summary'))

/**
 * Per-Command Flag Schemas
 *
 * Defines the valid flags for each CLI command to enable:
 * - Unknown flag detection
 * - Typo suggestions
 * - Accurate flag/value parsing in the preprocessor
 */

/**
 * Type of flag
 */
export type FlagType = 'boolean' | 'string'

/**
 * Flag specification
 */
export interface FlagSpec {
  /** Flag name without leading dashes (e.g., 'json') */
  name: string
  /** Flag type: boolean (no value) or string (takes value) */
  type: FlagType
  /** Short alias without leading dash (e.g., 'n' for --limit) */
  alias?: string
  /** Description for error messages */
  description?: string
}

/**
 * Command flag schema
 */
export interface CommandSchema {
  /** Command name */
  name: string
  /** Valid flags for this command */
  flags: FlagSpec[]
}

// ============================================================================
// Shared Flags (used by multiple commands)
// ============================================================================

const jsonFlag: FlagSpec = {
  name: 'json',
  type: 'boolean',
  description: 'Output as JSON',
}

const prettyFlag: FlagSpec = {
  name: 'pretty',
  type: 'boolean',
  description: 'Pretty-print JSON output',
}

const forceFlag: FlagSpec = {
  name: 'force',
  type: 'boolean',
  description: 'Force full rebuild',
}

const rootFlag: FlagSpec = {
  name: 'root',
  type: 'string',
  alias: 'r',
  description: 'Root directory',
}

// ============================================================================
// Per-Command Schemas
// ============================================================================

export const indexSchema: CommandSchema = {
  name: 'index',
  flags: [
    {
      name: 'embed',
      type: 'boolean',
      alias: 'e',
      description: 'Build semantic embeddings',
    },
    {
      name: 'watch',
      type: 'boolean',
      alias: 'w',
      description: 'Watch for changes',
    },
    forceFlag,
    jsonFlag,
    prettyFlag,
  ],
}

export const searchSchema: CommandSchema = {
  name: 'search',
  flags: [
    {
      name: 'structural',
      type: 'boolean',
      alias: 's',
      description: 'Force structural search',
    },
    {
      name: 'heading-only',
      type: 'boolean',
      alias: 'H',
      description: 'Search headings only',
    },
    {
      name: 'mode',
      type: 'string',
      alias: 'm',
      description: 'Force search mode (semantic or structural)',
    },
    {
      name: 'limit',
      type: 'string',
      alias: 'n',
      description: 'Maximum results',
    },
    { name: 'threshold', type: 'string', description: 'Similarity threshold' },
    jsonFlag,
    prettyFlag,
  ],
}

export const contextSchema: CommandSchema = {
  name: 'context',
  flags: [
    { name: 'tokens', type: 'string', alias: 't', description: 'Token budget' },
    { name: 'brief', type: 'boolean', description: 'Minimal output' },
    { name: 'full', type: 'boolean', description: 'Include full content' },
    jsonFlag,
    prettyFlag,
  ],
}

export const treeSchema: CommandSchema = {
  name: 'tree',
  flags: [jsonFlag, prettyFlag],
}

export const linksSchema: CommandSchema = {
  name: 'links',
  flags: [rootFlag, jsonFlag, prettyFlag],
}

export const backlinksSchema: CommandSchema = {
  name: 'backlinks',
  flags: [rootFlag, jsonFlag, prettyFlag],
}

export const statsSchema: CommandSchema = {
  name: 'stats',
  flags: [jsonFlag, prettyFlag],
}

// ============================================================================
// Schema Registry
// ============================================================================

/**
 * All command schemas indexed by command name
 */
export const commandSchemas: Record<string, CommandSchema> = {
  index: indexSchema,
  search: searchSchema,
  context: contextSchema,
  tree: treeSchema,
  links: linksSchema,
  backlinks: backlinksSchema,
  stats: statsSchema,
}

/**
 * Get schema for a command
 */
export const getCommandSchema = (
  commandName: string,
): CommandSchema | undefined => {
  return commandSchemas[commandName]
}

/**
 * Get all valid flag names for a command (both long and short forms)
 */
export const getValidFlags = (schema: CommandSchema): Set<string> => {
  const flags = new Set<string>()
  for (const spec of schema.flags) {
    flags.add(`--${spec.name}`)
    if (spec.alias) {
      flags.add(`-${spec.alias}`)
    }
  }
  return flags
}

/**
 * Check if a flag takes a value for a given command
 */
export const flagTakesValue = (
  schema: CommandSchema,
  flag: string,
): boolean => {
  // Handle --flag=value syntax
  if (flag.includes('=')) {
    return false // Value is already embedded
  }

  for (const spec of schema.flags) {
    if (
      flag === `--${spec.name}` ||
      (spec.alias && flag === `-${spec.alias}`)
    ) {
      return spec.type === 'string'
    }
  }
  return false
}

/**
 * Find the canonical name for a flag (for suggestions)
 */
export const getCanonicalFlagName = (
  schema: CommandSchema,
  flag: string,
): string | undefined => {
  for (const spec of schema.flags) {
    if (
      flag === `--${spec.name}` ||
      (spec.alias && flag === `-${spec.alias}`)
    ) {
      return `--${spec.name}`
    }
  }
  return undefined
}

/**
 * Section filtering utilities for extracting specific sections from markdown documents
 */

import type { MdDocument, MdSection } from '../core/types.js'

// ============================================================================
// Simple Glob Matching
// ============================================================================

/**
 * Simple glob pattern matching (supports * and ?)
 */
const globMatch = (text: string, pattern: string): boolean => {
  // Convert glob pattern to regex
  const regexPattern = pattern
    .replace(/[.+^${}()|[\]\\]/g, '\\$&') // Escape regex special chars except * and ?
    .replace(/\*/g, '.*')
    .replace(/\?/g, '.')

  const regex = new RegExp(`^${regexPattern}$`, 'i')
  return regex.test(text)
}

// ============================================================================
// Types
// ============================================================================

export interface SectionListItem {
  readonly number: string
  readonly heading: string
  readonly level: number
  readonly tokenCount: number
}

export interface SectionFilterOptions {
  /** If true, don't include nested subsections */
  readonly shallow?: boolean
}

// ============================================================================
// Section Map Building
// ============================================================================

/**
 * Build a flat list of all sections with their hierarchical numbers
 * e.g., "1", "1.1", "1.2", "2", "2.1", etc.
 */
export const buildSectionList = (document: MdDocument): SectionListItem[] => {
  const result: SectionListItem[] = []

  const processSection = (
    section: MdSection,
    prefix: string,
    index: number,
  ): void => {
    const number = prefix ? `${prefix}.${index + 1}` : `${index + 1}`

    result.push({
      number,
      heading: section.heading,
      level: section.level,
      tokenCount: section.metadata.tokenCount,
    })

    // Process children
    section.children.forEach((child, i) => {
      processSection(child, number, i)
    })
  }

  document.sections.forEach((section, i) => {
    processSection(section, '', i)
  })

  return result
}

/**
 * Format section list for display
 */
export const formatSectionList = (sections: SectionListItem[]): string => {
  const lines: string[] = []

  for (const section of sections) {
    // Indent based on dots in number
    const depth = (section.number.match(/\./g) || []).length
    const indent = '   '.repeat(depth)
    lines.push(
      `${indent}${section.number}. ${section.heading} (${section.tokenCount} tokens)`,
    )
  }

  return lines.join('\n')
}

// ============================================================================
// Section Matching
// ============================================================================

/**
 * Check if a section matches a selector (by number, exact name, or glob pattern)
 */
const matchesSelector = (
  section: SectionListItem,
  selector: string,
): boolean => {
  // Check if it's a number match (e.g., "5.3")
  if (/^[\d.]+$/.test(selector)) {
    // Exact number match
    return section.number === selector
  }

  // Check for exact heading match (case-insensitive)
  if (section.heading.toLowerCase() === selector.toLowerCase()) {
    return true
  }

  // Check for glob pattern match
  if (selector.includes('*') || selector.includes('?')) {
    return globMatch(section.heading, selector)
  }

  // Partial match (contains)
  return section.heading.toLowerCase().includes(selector.toLowerCase())
}

/**
 * Find all sections matching a selector
 */
export const findMatchingSections = (
  sectionList: SectionListItem[],
  selector: string,
): SectionListItem[] => {
  return sectionList.filter((s) => matchesSelector(s, selector))
}

/**
 * Get all descendant section numbers for a given section number
 */
const getDescendantNumbers = (
  sectionList: SectionListItem[],
  parentNumber: string,
): Set<string> => {
  const result = new Set<string>()
  const prefix = `${parentNumber}.`

  for (const section of sectionList) {
    if (section.number.startsWith(prefix)) {
      result.add(section.number)
    }
  }

  return result
}

// ============================================================================
// Section Content Extraction
// ============================================================================

/**
 * Extract content for specific sections from a document
 */
export const extractSectionContent = (
  document: MdDocument,
  selector: string,
  options: SectionFilterOptions = {},
): {
  sections: MdSection[]
  matchedNumbers: string[]
} => {
  const sectionList = buildSectionList(document)
  const matchedSections = findMatchingSections(sectionList, selector)

  if (matchedSections.length === 0) {
    return { sections: [], matchedNumbers: [] }
  }

  // Get all section numbers to include
  const numbersToInclude = new Set<string>()
  const matchedNumbers: string[] = []

  for (const matched of matchedSections) {
    numbersToInclude.add(matched.number)
    matchedNumbers.push(matched.number)

    if (!options.shallow) {
      // Include all descendants
      const descendants = getDescendantNumbers(sectionList, matched.number)
      for (const desc of descendants) {
        numbersToInclude.add(desc)
      }
    }
  }

  // Build a map from section number to section for efficient lookup
  const numberToSection = new Map<string, MdSection>()

  const mapSections = (
    sections: readonly MdSection[],
    prefix: string,
  ): void => {
    sections.forEach((section, i) => {
      const number = prefix ? `${prefix}.${i + 1}` : `${i + 1}`
      numberToSection.set(number, section)
      mapSections(section.children, number)
    })
  }

  mapSections(document.sections, '')

  // Extract matching sections
  const extractedSections: MdSection[] = []

  for (const number of matchedNumbers) {
    const section = numberToSection.get(number)
    if (section) {
      if (options.shallow) {
        // Clone without children for shallow mode
        extractedSections.push({
          ...section,
          children: [],
        })
      } else {
        extractedSections.push(section)
      }
    }
  }

  return { sections: extractedSections, matchedNumbers }
}

/**
 * Format extracted sections as markdown content
 */
export const formatExtractedSections = (sections: MdSection[]): string => {
  const formatSection = (
    section: MdSection,
    includeChildren: boolean,
  ): string => {
    const lines: string[] = []

    // Add heading
    const headingPrefix = '#'.repeat(section.level)
    lines.push(`${headingPrefix} ${section.heading}`)
    lines.push('')

    // Add content (strip the heading line if it starts with #)
    const contentLines = section.content.split('\n')
    const contentWithoutHeading = contentLines
      .filter((line, i) => i > 0 || !line.startsWith('#'))
      .join('\n')
      .trim()

    if (contentWithoutHeading) {
      lines.push(contentWithoutHeading)
    }

    if (includeChildren) {
      for (const child of section.children) {
        lines.push('')
        lines.push(formatSection(child, true))
      }
    }

    return lines.join('\n')
  }

  return sections.map((s) => formatSection(s, true)).join('\n\n')
}

/**
 * Summarization engine for md-tldr
 *
 * Provides hierarchical summarization and multi-document context assembly
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'
import type { MdDocument, MdSection } from '../core/types.js'
import { parseFile } from '../parser/parser.js'
import { countTokensApprox } from '../utils/tokens.js'
import { formatSummary as formatSummaryImpl } from './formatters.js'

// ============================================================================
// Types
// ============================================================================

export type CompressionLevel = 'brief' | 'summary' | 'full'

export interface SummarizeOptions {
  /** Compression level */
  readonly level?: CompressionLevel | undefined
  /** Maximum tokens for output */
  readonly maxTokens?: number | undefined
}

export interface SectionSummary {
  readonly heading: string
  readonly level: number
  readonly originalTokens: number
  readonly summaryTokens: number
  readonly summary: string
  readonly children: readonly SectionSummary[]
  readonly hasCode: boolean
  readonly hasList: boolean
  readonly hasTable: boolean
}

export interface DocumentSummary {
  readonly path: string
  readonly title: string
  readonly originalTokens: number
  readonly summaryTokens: number
  readonly compressionRatio: number
  readonly sections: readonly SectionSummary[]
  readonly keyTopics: readonly string[]
  /** True if content was truncated to fit budget */
  readonly truncated?: boolean
  /** Number of sections that were omitted due to budget constraints */
  readonly truncatedCount?: number
}

export interface AssembleContextOptions {
  /** Total token budget */
  readonly budget: number
  /** Compression level for each source */
  readonly level?: CompressionLevel | undefined
}

export interface AssembledContext {
  readonly sources: readonly SourceContext[]
  readonly totalTokens: number
  readonly budget: number
  readonly overflow: readonly string[]
}

export interface SourceContext {
  readonly path: string
  readonly title: string
  readonly tokens: number
  readonly content: string
}

// ============================================================================
// Constants
// ============================================================================

/** Token budgets per compression level */
const TOKEN_BUDGETS: Record<CompressionLevel, number> = {
  brief: 100,
  summary: 500,
  full: Infinity,
}

/** Minimum character length for a sentence to be considered meaningful */
const MIN_SENTENCE_LENGTH = 10

/** Score weights for sentence importance heuristics */
const SENTENCE_SCORE_DEFINITION = 2 // sentences with colons (definitions)
const SENTENCE_SCORE_PROPER_START = 1 // sentences starting with capital
const SENTENCE_SCORE_MEDIUM_LENGTH = 1 // sentences in ideal length range
const SENTENCE_SCORE_EMPHASIS = 1 // sentences with emphasis or code

/** Ideal sentence length range for summaries */
const SENTENCE_LENGTH_MIN = 50
const SENTENCE_LENGTH_MAX = 200

/** Target compression ratio for summaries (30% of original) */
const SUMMARY_COMPRESSION_RATIO = 0.3

/** Minimum tokens for any section summary */
const MIN_SECTION_TOKENS = 20

/** Minimum sentences to include in any summary */
const MIN_SUMMARY_SENTENCES = 2

/** Approximate tokens per sentence (for calculating max sentences) */
const TOKENS_PER_SENTENCE_ESTIMATE = 30

/** Topic heading length constraints */
const MIN_TOPIC_LENGTH = 2
const MAX_TOPIC_LENGTH = 50

/** Maximum topics to extract from a document */
const MAX_TOPICS = 10

/** Minimum remaining budget to include partial content */
const MIN_PARTIAL_BUDGET = 50

// ============================================================================
// Section Summarization
// ============================================================================

const extractKeyPoints = (content: string, maxSentences: number): string[] => {
  // Split into sentences
  const sentences = content
    .replace(/\n+/g, ' ')
    .split(/(?<=[.!?])\s+/)
    .filter((s) => s.trim().length > MIN_SENTENCE_LENGTH)

  if (sentences.length <= maxSentences) {
    return sentences
  }

  // Simple heuristic: prefer sentences with key indicators
  const scored = sentences.map((s) => {
    let score = 0
    // Prefer sentences with:
    if (s.includes(':')) score += SENTENCE_SCORE_DEFINITION
    if (/^[A-Z]/.test(s)) score += SENTENCE_SCORE_PROPER_START
    if (s.length > SENTENCE_LENGTH_MIN && s.length < SENTENCE_LENGTH_MAX)
      score += SENTENCE_SCORE_MEDIUM_LENGTH
    if (/\*\*|`/.test(s)) score += SENTENCE_SCORE_EMPHASIS
    return { sentence: s, score }
  })

  // Sort by score and take top sentences
  scored.sort((a, b) => b.score - a.score)
  return scored.slice(0, maxSentences).map((s) => s.sentence)
}

const summarizeSection = (
  section: MdSection,
  level: CompressionLevel,
): SectionSummary => {
  const originalTokens = section.metadata.tokenCount

  // Get children summaries first
  const children = section.children.map((child) =>
    summarizeSection(child, level),
  )

  // Calculate target tokens based on level
  const targetTokens = Math.min(
    TOKEN_BUDGETS[level],
    Math.max(originalTokens * SUMMARY_COMPRESSION_RATIO, MIN_SECTION_TOKENS),
  )

  let summary: string

  if (level === 'full' || originalTokens <= targetTokens) {
    // Include full content for "full" level or if already small
    // Use plainText instead of content to avoid including the heading markdown
    // (the heading is output separately by the formatter)
    summary = section.plainText
  } else if (level === 'brief') {
    // Just heading and metadata for brief
    const meta: string[] = []
    if (section.metadata.hasCode) meta.push('code')
    if (section.metadata.hasList) meta.push('list')
    if (section.metadata.hasTable) meta.push('table')
    summary = meta.length > 0 ? `[${meta.join(', ')}]` : ''
  } else {
    // Summary level: extract key points
    const maxSentences = Math.max(
      MIN_SUMMARY_SENTENCES,
      Math.floor(targetTokens / TOKENS_PER_SENTENCE_ESTIMATE),
    )
    const keyPoints = extractKeyPoints(section.plainText, maxSentences)

    if (keyPoints.length > 0) {
      summary = keyPoints.join(' ')
    } else {
      // Fallback: truncate
      const words = section.plainText.split(/\s+/).slice(0, targetTokens)
      summary =
        words.join(' ') +
        (words.length < section.plainText.split(/\s+/).length ? '...' : '')
    }
  }

  const summaryTokens = countTokensApprox(summary)

  return {
    heading: section.heading,
    level: section.level,
    originalTokens,
    summaryTokens,
    summary,
    children,
    hasCode: section.metadata.hasCode,
    hasList: section.metadata.hasList,
    hasTable: section.metadata.hasTable,
  }
}

// ============================================================================
// Document Summarization
// ============================================================================

const extractTopics = (document: MdDocument): string[] => {
  const topics: Set<string> = new Set()

  // Extract from headings
  const processSection = (section: MdSection) => {
    // Clean heading and add as topic
    const cleanHeading = section.heading
      .replace(/[:#\-_]/g, ' ')
      .trim()
      .toLowerCase()
    if (
      cleanHeading.length > MIN_TOPIC_LENGTH &&
      cleanHeading.length < MAX_TOPIC_LENGTH
    ) {
      topics.add(cleanHeading)
    }

    for (const child of section.children) {
      processSection(child)
    }
  }

  for (const section of document.sections) {
    processSection(section)
  }

  // Also extract from frontmatter tags if present
  const frontmatter = document.frontmatter as Record<string, unknown>
  if (frontmatter.tags && Array.isArray(frontmatter.tags)) {
    for (const tag of frontmatter.tags) {
      if (typeof tag === 'string') {
        topics.add(tag.toLowerCase())
      }
    }
  }

  return Array.from(topics).slice(0, MAX_TOPICS)
}

export const summarizeDocument = (
  document: MdDocument,
  options: SummarizeOptions = {},
): DocumentSummary => {
  const level = options.level ?? 'summary'
  const maxTokens = options.maxTokens ?? TOKEN_BUDGETS[level]

  // Summarize all sections
  const allSections = document.sections.map((s) => summarizeSection(s, level))

  // Calculate totals and collect all flattened sections with their tokens
  const originalTokens = document.metadata.tokenCount
  let totalSummaryTokens = 0
  const flatSections: SectionSummary[] = []

  const flattenWithTokens = (section: SectionSummary) => {
    flatSections.push(section)
    totalSummaryTokens += section.summaryTokens
    for (const child of section.children) {
      flattenWithTokens(child)
    }
  }

  for (const section of allSections) {
    flattenWithTokens(section)
  }

  // Calculate formatting overhead dynamically based on actual content
  // Header includes: "# {title}\nPath: {path}\nTokens: X (Y% reduction from Z)\n"
  // Plus topics line if present, plus possible truncation warning
  const topics = extractTopics(document)
  const headerTemplate = `# ${document.title}\nPath: ${document.path}\nTokens: 9999 (99% reduction from ${document.metadata.tokenCount})\n`
  const topicsLine =
    topics.length > 0 ? `\n**Topics:** ${topics.join(', ')}\n` : ''
  const truncationWarning =
    '\n⚠️ TRUNCATED: 999 sections omitted to fit token budget'
  // Add all possible overhead plus a generous safety margin (20% of overhead + 20 base)
  // This accounts for variance in token estimation
  const baseOverhead = countTokensApprox(
    headerTemplate + topicsLine + truncationWarning,
  )
  const formattingOverhead = Math.ceil(baseOverhead * 1.2) + 20
  const contentBudget = maxTokens - formattingOverhead

  // If over budget, truncate sections to fit
  let truncated = false
  let truncatedCount = 0
  let sections: SectionSummary[]
  let summaryTokens: number

  if (totalSummaryTokens > contentBudget && contentBudget > 0) {
    // Need to truncate - use greedy tree traversal that can include children
    // even when parent doesn't fit (orphan rescue)
    let tokensUsed = 0

    // Process tree with orphan rescue: if parent doesn't fit, still try children
    const truncateSections = (
      sectionList: readonly SectionSummary[],
    ): SectionSummary[] => {
      const result: SectionSummary[] = []

      for (const section of sectionList) {
        const sectionOwnTokens = section.summaryTokens
        const fitsInBudget = tokensUsed + sectionOwnTokens <= contentBudget

        if (fitsInBudget) {
          // Section fits - include it and recursively process children
          tokensUsed += sectionOwnTokens
          const truncatedChildren = truncateSections(section.children)
          result.push({
            ...section,
            children: truncatedChildren,
          })
        } else {
          // Section doesn't fit - but still try to rescue children (orphan rescue)
          truncatedCount++
          const rescuedChildren = truncateSections(section.children)
          // Add rescued children as top-level items in result
          result.push(...rescuedChildren)
        }
      }

      return result
    }

    sections = truncateSections(allSections)
    summaryTokens = tokensUsed
    truncated = truncatedCount > 0
  } else {
    sections = allSections
    summaryTokens = totalSummaryTokens
  }

  const compressionRatio =
    originalTokens > 0 ? 1 - summaryTokens / originalTokens : 0

  const result: DocumentSummary = {
    path: document.path,
    title: document.title,
    originalTokens,
    summaryTokens,
    compressionRatio,
    sections,
    keyTopics: topics,
  }

  if (truncated) {
    return {
      ...result,
      truncated: true,
      truncatedCount,
    }
  }

  return result
}

export const summarizeFile = (
  filePath: string,
  options: SummarizeOptions = {},
): Effect.Effect<DocumentSummary, Error> =>
  Effect.gen(function* () {
    const document = yield* parseFile(filePath).pipe(
      Effect.mapError((e) => new Error(`${e._tag}: ${e.message}`)),
    )

    return summarizeDocument(document, options)
  })

// ============================================================================
// Format Summary for Output (re-exported from formatters.ts)
// ============================================================================

export { type FormatSummaryOptions, formatSummary } from './formatters.js'

// ============================================================================
// Multi-Document Context Assembly
// ============================================================================

export const assembleContext = (
  rootPath: string,
  sourcePaths: readonly string[],
  options: AssembleContextOptions,
): Effect.Effect<AssembledContext, Error> =>
  Effect.gen(function* () {
    const budget = options.budget
    const level = options.level ?? 'summary'

    const sources: SourceContext[] = []
    const overflow: string[] = []
    let totalTokens = 0

    // Calculate per-source budget (even distribution)
    const perSourceBudget = Math.floor(budget / sourcePaths.length)

    for (const sourcePath of sourcePaths) {
      const resolvedPath = path.isAbsolute(sourcePath)
        ? sourcePath
        : path.join(rootPath, sourcePath)

      try {
        const summary = yield* summarizeFile(resolvedPath, {
          level,
          maxTokens: perSourceBudget,
        })

        const content = formatSummaryImpl(summary)
        // Count actual formatted output tokens, not pre-format summary tokens
        const tokens = countTokensApprox(content)

        if (totalTokens + tokens <= budget) {
          sources.push({
            path: path.relative(rootPath, resolvedPath),
            title: summary.title,
            tokens,
            content,
          })
          totalTokens += tokens
        } else {
          // Over budget
          const remaining = budget - totalTokens
          if (remaining > MIN_PARTIAL_BUDGET) {
            // Include partial if we have some room
            const briefSummary = yield* summarizeFile(resolvedPath, {
              level: 'brief',
              maxTokens: remaining,
            })
            const briefContent = formatSummaryImpl(briefSummary)
            // Count actual formatted output tokens, not pre-format summary tokens
            const briefTokens = countTokensApprox(briefContent)

            sources.push({
              path: path.relative(rootPath, resolvedPath),
              title: briefSummary.title,
              tokens: briefTokens,
              content: briefContent,
            })
            totalTokens += briefTokens
          } else {
            overflow.push(path.relative(rootPath, resolvedPath))
          }
        }
      } catch (_e) {
        // Skip files that can't be processed
        overflow.push(sourcePath)
      }
    }

    return {
      sources,
      totalTokens,
      budget,
      overflow,
    }
  })

