// ============================================================================
// Measure Token Reduction
// ============================================================================

export interface TokenReductionReport {
  readonly originalTokens: number
  readonly summaryTokens: number
  readonly reduction: number
  readonly reductionPercent: number
}

export const measureReduction = async (
  filePath: string,
  level: CompressionLevel = 'summary',
): Promise<TokenReductionReport> => {
  // Read original content
  const originalContent = await fs.readFile(filePath, 'utf-8')
  const originalTokens = countTokensApprox(originalContent)

  // Get summary
  const result = await Effect.runPromise(
    summarizeFile(filePath, { level }).pipe(
      Effect.catchAll(() => Effect.succeed(null)),
    ),
  )

  if (!result) {
    return {
      originalTokens,
      summaryTokens: originalTokens,
      reduction: 0,
      reductionPercent: 0,
    }
  }

  const summaryTokens = result.summaryTokens
  const reduction = originalTokens - summaryTokens
  const reductionPercent = originalTokens > 0 ? reduction / originalTokens : 0

  return {
    originalTokens,
    summaryTokens,
    reduction,
    reductionPercent,
  }
}

/**
 * Formatting functions for summarization output
 *
 * Responsible for converting summary data structures into human-readable text
 */

import { countTokensApprox } from '../utils/tokens.js'
import type {
  AssembledContext,
  DocumentSummary,
  SectionSummary,
} from './summarizer.js'

export interface FormatSummaryOptions {
  /** Maximum tokens for formatted output. If exceeded, sections will be truncated. */
  readonly maxTokens?: number
}

/**
 * Format a document summary for display
 *
 * Outputs a markdown-formatted summary with:
 * - Title and path
 * - Accurate token count (of the formatted output)
 * - Key topics
 * - Hierarchical section summaries
 *
 * When maxTokens is specified, strictly enforces the budget by iteratively
 * removing sections until the output fits.
 */
export const formatSummary = (
  summary: DocumentSummary,
  options: FormatSummaryOptions = {},
): string => {
  const maxTokens = options.maxTokens

  // Flatten sections in order for incremental building
  // Uses depth-first order so children follow parents - this enables "orphan rescue"
  // where children can still be included even if their parent was too large
  const flatSections: { section: SectionSummary; depth: number }[] = []

  const collectSections = (section: SectionSummary, depth: number = 0) => {
    flatSections.push({ section, depth })
    for (const child of section.children) {
      collectSections(child, depth + 1)
    }
  }

  for (const section of summary.sections) {
    collectSections(section)
  }

  // Helper to build output with a given set of section indices
  const buildOutput = (
    includedSectionIndices: Set<number>,
    showTruncationWarning: boolean,
    truncationCount: number,
    includeTopics: boolean,
  ): string => {
    const lines: string[] = []
    lines.push(`# ${summary.title}`)
    lines.push(`Path: ${summary.path}`)

    // Placeholder for token line - we'll calculate actual tokens after building
    const tokenLineIndex = lines.length
    lines.push('PLACEHOLDER')

    if (showTruncationWarning && truncationCount > 0) {
      const totalTruncated = truncationCount + (summary.truncatedCount ?? 0)
      lines.push(
        `⚠️ TRUNCATED: ${totalTruncated} sections omitted to fit token budget`,
      )
    }
    lines.push('')

    const fullTopicsLine =
      summary.keyTopics.length > 0
        ? `**Topics:** ${summary.keyTopics.join(', ')}`
        : ''

    if (includeTopics && fullTopicsLine) {
      lines.push(fullTopicsLine)
      lines.push('')
    }

    // Build section content
    const sectionLines: string[] = []
    for (let i = 0; i < flatSections.length; i++) {
      if (!includedSectionIndices.has(i)) continue
      const { section, depth } = flatSections[i]!
      const indent = '  '.repeat(depth)
      const prefix = '#'.repeat(section.level)
      sectionLines.push(`${indent}${prefix} ${section.heading}`)
      if (section.summary) {
        sectionLines.push(`${indent}${section.summary}`)
      }
    }

    lines.push(sectionLines.join('\n'))

    // Calculate actual token count for this output
    // Build output without token line first
    const tempOutput = lines.join('\n')
    const tokensWithoutLine = countTokensApprox(
      tempOutput.replace('PLACEHOLDER', ''),
    )

    // The token line itself adds tokens - iterate to find stable count
    // Token line format: "Tokens: XXX (YY% reduction from ZZZ)"
    let estimatedTotal = tokensWithoutLine + 8 // Initial estimate for token line
    for (let iter = 0; iter < 3; iter++) {
      const testTokenLine = `Tokens: ${estimatedTotal} (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`
      const testOutput = tempOutput.replace('PLACEHOLDER', testTokenLine)
      const actualTotal = countTokensApprox(testOutput)
      if (actualTotal === estimatedTotal) break
      estimatedTotal = actualTotal
    }

    // Final token line with converged count
    const finalTokenLine = `Tokens: ${estimatedTotal} (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`
    lines[tokenLineIndex] = finalTokenLine

    return lines.join('\n')
  }

  // If no budget, include everything
  if (maxTokens === undefined) {
    const allIndices = new Set(flatSections.map((_, i) => i))
    const hasPriorTruncation = summary.truncated && summary.truncatedCount
    return buildOutput(allIndices, !!hasPriorTruncation, 0, true)
  }

  // With budget: greedily add sections, then validate and trim if needed
  const includedIndices = new Set<number>()
  let truncatedCount = 0
  let includeTopics = true

  // First pass: estimate what fits using conservative token counting
  // Add 15% safety margin to each section's token count
  const SAFETY_MARGIN = 1.15

  // Calculate minimum header overhead (title, path, token line)
  const minHeaderTemplate = [
    `# ${summary.title}`,
    `Path: ${summary.path}`,
    `Tokens: 9999 (${(summary.compressionRatio * 100).toFixed(0)}% reduction from ${summary.originalTokens})`,
    '',
    '',
  ].join('\n')
  const minHeaderTokens = Math.ceil(
    countTokensApprox(minHeaderTemplate) * SAFETY_MARGIN,
  )

  // Calculate topics overhead
  const fullTopicsLine =
    summary.keyTopics.length > 0
      ? `**Topics:** ${summary.keyTopics.join(', ')}\n`
      : ''
  const topicsTokens = fullTopicsLine
    ? Math.ceil(countTokensApprox(fullTopicsLine) * SAFETY_MARGIN)
    : 0

  // Truncation warning overhead
  const truncationWarningTokens = Math.ceil(
    countTokensApprox(
      `⚠️ TRUNCATED: 999 sections omitted to fit token budget\n`,
    ) * SAFETY_MARGIN,
  )

  // Start with header + topics
  let headerTokens = minHeaderTokens + topicsTokens

  // If header alone exceeds budget, drop topics
  if (headerTokens >= maxTokens) {
    includeTopics = false
    headerTokens = minHeaderTokens
  }

  // Calculate content budget (reserve space for potential truncation warning)
  let contentBudget = maxTokens - headerTokens - truncationWarningTokens
  let tokensUsed = 0

  // Greedy section selection
  for (let i = 0; i < flatSections.length; i++) {
    const { section, depth } = flatSections[i]!
    const indent = '  '.repeat(depth)
    const prefix = '#'.repeat(section.level)
    const sectionContent = section.summary
      ? `${indent}${prefix} ${section.heading}\n${indent}${section.summary}`
      : `${indent}${prefix} ${section.heading}`

    const sectionTokens = Math.ceil(
      countTokensApprox(sectionContent) * SAFETY_MARGIN,
    )

    if (tokensUsed + sectionTokens <= contentBudget) {
      includedIndices.add(i)
      tokensUsed += sectionTokens
    } else {
      truncatedCount++
    }
  }

  // If nothing was truncated, we can use the full content budget
  if (truncatedCount === 0) {
    contentBudget += truncationWarningTokens
  }

  // Build output and validate it fits
  let output = buildOutput(
    includedIndices,
    truncatedCount > 0,
    truncatedCount,
    includeTopics,
  )
  let actualTokens = countTokensApprox(output)

  // Final validation loop: remove sections from the end until we fit
  // This handles any estimation errors
  const sortedIndices = Array.from(includedIndices).sort((a, b) => b - a) // Reverse order
  let removalIndex = 0

  while (actualTokens > maxTokens && removalIndex < sortedIndices.length) {
    // Remove the last section
    const indexToRemove = sortedIndices[removalIndex]!
    includedIndices.delete(indexToRemove)
    truncatedCount++
    removalIndex++

    // Rebuild and recheck
    output = buildOutput(includedIndices, true, truncatedCount, includeTopics)
    actualTokens = countTokensApprox(output)
  }

  // If still over budget and we haven't dropped topics yet, try that
  if (actualTokens > maxTokens && includeTopics) {
    includeTopics = false
    output = buildOutput(includedIndices, true, truncatedCount, includeTopics)
    actualTokens = countTokensApprox(output)
  }

  // If still over budget, try dropping the truncation warning as last resort
  // (only if we're showing it and have truncated sections)
  if (actualTokens > maxTokens && truncatedCount > 0) {
    output = buildOutput(includedIndices, false, truncatedCount, includeTopics)
    actualTokens = countTokensApprox(output)
  }

  return output
}

/**
 * Format assembled context for display
 *
 * Outputs a combined view of multiple document summaries with:
 * - Header showing total tokens and source count
 * - Individual source summaries separated by dividers
 * - Overflow list for sources that didn't fit the budget
 */
export const formatAssembledContext = (context: AssembledContext): string => {
  const lines: string[] = []

  lines.push('# Context Assembly')
  lines.push(`Total tokens: ${context.totalTokens}/${context.budget}`)
  lines.push(`Sources: ${context.sources.length}`)
  lines.push('')

  for (const source of context.sources) {
    lines.push('---')
    lines.push('')
    lines.push(source.content)
  }

  if (context.overflow.length > 0) {
    lines.push('---')
    lines.push('')
    lines.push('## Overflow (not included due to budget)')
    for (const overflowPath of context.overflow) {
      lines.push(`- ${overflowPath}`)
    }
  }

  return lines.join('\n')
}

/**
 * SEARCH Command
 *
 * Search markdown content by meaning or heading pattern.
 */

import * as path from 'node:path'
import { Args, Command, Options } from '@effect/cli'
import { Console, Effect, Option } from 'effect'
import { semanticSearch } from '../../embeddings/semantic-search.js'
import { search, searchContent } from '../../search/searcher.js'
import { jsonOption, prettyOption } from '../options.js'
import { formatJson, hasEmbeddings, isRegexPattern } from '../utils.js'

export const searchCommand = Command.make(
  'search',
  {
    query: Args.text({ name: 'query' }).pipe(
      Args.withDescription('Search query (natural language or regex pattern)'),
    ),
    path: Args.directory({ name: 'path' }).pipe(
      Args.withDescription('Directory to search in'),
      Args.withDefault('.'),
    ),
    structural: Options.boolean('structural').pipe(
      Options.withAlias('s'),
      Options.withDescription('Force structural search (headings only)'),
      Options.withDefault(false),
    ),
    headingOnly: Options.boolean('heading-only').pipe(
      Options.withAlias('H'),
      Options.withDescription('Search headings only (not content)'),
      Options.withDefault(false),
    ),
    mode: Options.choice('mode', ['semantic', 'structural']).pipe(
      Options.withAlias('m'),
      Options.withDescription('Force search mode: semantic or structural'),
      Options.optional,
    ),
    limit: Options.integer('limit').pipe(
      Options.withAlias('n'),
      Options.withDescription('Maximum results'),
      Options.withDefault(10),
    ),
    threshold: Options.float('threshold').pipe(
      Options.withDescription('Similarity threshold for semantic search (0-1)'),
      Options.withDefault(0.5),
    ),
    json: jsonOption,
    pretty: prettyOption,
  },
  ({
    query,
    path: dirPath,
    structural,
    headingOnly,
    mode,
    limit,
    threshold,
    json,
    pretty,
  }) =>
    Effect.gen(function* () {
      const resolvedDir = path.resolve(dirPath)

      // Check for embeddings
      const embedsExist = yield* Effect.promise(() =>
        hasEmbeddings(resolvedDir),
      )

      // Determine search mode
      // Priority: --mode flag > --structural flag > regex pattern > embeddings availability
      let useStructural: boolean
      let modeReason: string

      const modeValue = Option.getOrUndefined(mode)

      if (modeValue === 'semantic') {
        if (!embedsExist) {
          yield* Effect.fail(
            new Error(
              'Semantic search requires embeddings. Run "mdtldr index --embed" first.',
            ),
          )
        }
        useStructural = false
        modeReason = '--mode semantic'
      } else if (modeValue === 'structural') {
        useStructural = true
        modeReason = '--mode structural'
      } else if (structural) {
        useStructural = true
        modeReason = '--structural flag'
      } else if (isRegexPattern(query)) {
        useStructural = true
        modeReason = 'regex pattern detected'
      } else if (!embedsExist) {
        useStructural = true
        modeReason = 'no embeddings'
      } else {
        useStructural = false
        modeReason = 'embeddings available'
      }

      const modeIndicator = useStructural ? '[structural]' : '[semantic]'

      if (useStructural) {
        // Structural search - content by default, heading-only if flag set
        const results = headingOnly
          ? yield* search(resolvedDir, { heading: query, limit })
          : yield* searchContent(resolvedDir, { content: query, limit })

        if (json) {
          const output = {
            mode: 'structural',
            modeReason,
            query,
            results: results.map((r) => ({
              path: r.section.documentPath,
              heading: r.section.heading,
              level: r.section.level,
              tokens: r.section.tokenCount,
              line: r.section.startLine,
              matches: r.matches?.map((m) => ({
                lineNumber: m.lineNumber,
                line: m.line,
              })),
            })),
          }
          yield* Console.log(formatJson(output, pretty))
        } else {
          const searchType = headingOnly ? 'Heading' : 'Content'
          yield* Console.log(
            `${modeIndicator} ${searchType} search: "${query}"`,
          )
          yield* Console.log(`Results: ${results.length}`)
          yield* Console.log('')

          for (const result of results) {
            const levelMarker = '#'.repeat(result.section.level)
            yield* Console.log(
              `  ${result.section.documentPath}:${result.section.startLine}`,
            )
            yield* Console.log(
              `    ${levelMarker} ${result.section.heading} (${result.section.tokenCount} tokens)`,
            )

            // Show match snippets with line numbers
            if (result.matches && result.matches.length > 0) {
              yield* Console.log('')
              for (const match of result.matches.slice(0, 3)) {
                // Show first 3 matches per section
                yield* Console.log(`    Line ${match.lineNumber}:`)
                // Indent snippet lines
                const snippetLines = match.snippet.split('\n')
                for (const line of snippetLines) {
                  yield* Console.log(`      ${line}`)
                }
              }
              if (result.matches.length > 3) {
                yield* Console.log(
                  `    ... and ${result.matches.length - 3} more matches`,
                )
              }
            }
            yield* Console.log('')
          }
        }
      } else {
        // Semantic search
        const results = yield* semanticSearch(resolvedDir, query, {
          limit,
          threshold,
        })

        if (json) {
          const output = {
            mode: 'semantic',
            modeReason,
            query,
            results,
          }
          yield* Console.log(formatJson(output, pretty))
        } else {
          yield* Console.log(`${modeIndicator} Semantic search: "${query}"`)
          yield* Console.log(`Results: ${results.length}`)
          yield* Console.log('')

          for (const result of results) {
            const similarity = (result.similarity * 100).toFixed(1)
            yield* Console.log(`  ${result.documentPath}`)
            yield* Console.log(`    ${result.heading} (${similarity}% match)`)
            yield* Console.log('')
          }
        }
      }
    }),
).pipe(Command.withDescription('Search by meaning or structure'))

/**
 * Structural search for md-tldr
 */

import * as fs from 'node:fs/promises'
import * as path from 'node:path'
import { Effect } from 'effect'

import {
  createStorage,
  loadDocumentIndex,
  loadSectionIndex,
} from '../index/storage.js'
import type { DocumentEntry, SectionEntry } from '../index/types.js'
import {
  buildHighlightPattern,
  evaluateQuery,
  isAdvancedQuery,
  type ParsedQuery,
  parseQuery,
} from './query-parser.js'

// ============================================================================
// Search Options
// ============================================================================

export interface SearchOptions {
  /** Filter by heading pattern (regex) */
  readonly heading?: string | undefined
  /** Search within section content (regex) */
  readonly content?: string | undefined
  /** Filter by file path pattern (glob-like) */
  readonly pathPattern?: string | undefined
  /** Only sections with code blocks */
  readonly hasCode?: boolean | undefined
  /** Only sections with lists */
  readonly hasList?: boolean | undefined
  /** Only sections with tables */
  readonly hasTable?: boolean | undefined
  /** Minimum heading level */
  readonly minLevel?: number | undefined
  /** Maximum heading level */
  readonly maxLevel?: number | undefined
  /** Maximum results */
  readonly limit?: number | undefined
}

export interface ContentMatch {
  /** The line number where match was found (1-based) */
  readonly lineNumber: number
  /** The matching line text */
  readonly line: string
  /** Snippet showing match context (lines before and after) */
  readonly snippet: string
}

export interface SearchResult {
  readonly section: SectionEntry
  readonly document: DocumentEntry
  readonly sectionContent?: string
  /** Matches found within the content (when content search is used) */
  readonly matches?: readonly ContentMatch[]
}

// ============================================================================
// Path Matching
// ============================================================================

const matchPath = (filePath: string, pattern: string): boolean => {
  // Simple glob-like matching
  const regexPattern = pattern
    .replace(/\./g, '\\.')
    .replace(/\*/g, '.*')
    .replace(/\?/g, '.')

  const regex = new RegExp(`^${regexPattern}$`, 'i')
  return regex.test(filePath)
}

// ============================================================================
// Search Implementation
// ============================================================================

export const search = (
  rootPath: string,
  options: SearchOptions = {},
): Effect.Effect<readonly SearchResult[], Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)

    const docIndex = yield* loadDocumentIndex(storage)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!docIndex || !sectionIndex) {
      return []
    }

    const results: SearchResult[] = []
    const headingRegex = options.heading
      ? new RegExp(options.heading, 'i')
      : null

    for (const section of Object.values(sectionIndex.sections)) {
      // Filter by heading pattern
      if (headingRegex && !headingRegex.test(section.heading)) {
        continue
      }

      // Filter by path pattern
      if (
        options.pathPattern &&
        !matchPath(section.documentPath, options.pathPattern)
      ) {
        continue
      }

      // Filter by code blocks
      if (
        options.hasCode !== undefined &&
        section.hasCode !== options.hasCode
      ) {
        continue
      }

      // Filter by lists
      if (
        options.hasList !== undefined &&
        section.hasList !== options.hasList
      ) {
        continue
      }

      // Filter by tables
      if (
        options.hasTable !== undefined &&
        section.hasTable !== options.hasTable
      ) {
        continue
      }

      // Filter by level range
      if (options.minLevel !== undefined && section.level < options.minLevel) {
        continue
      }

      if (options.maxLevel !== undefined && section.level > options.maxLevel) {
        continue
      }

      const document = docIndex.documents[section.documentPath]
      if (document) {
        results.push({ section, document })
      }

      // Check limit
      if (options.limit !== undefined && results.length >= options.limit) {
        break
      }
    }

    return results
  })

// ============================================================================
// Content Search Implementation
// ============================================================================

/**
 * Search within section content.
 * Supports boolean operators (AND, OR, NOT) and quoted phrases.
 * Falls back to regex for simple patterns.
 */
export const searchContent = (
  rootPath: string,
  options: SearchOptions = {},
): Effect.Effect<readonly SearchResult[], Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)

    const docIndex = yield* loadDocumentIndex(storage)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!docIndex || !sectionIndex) {
      return []
    }

    // Parse content query - use boolean parser if advanced, else regex
    let parsedQuery: ParsedQuery | null = null
    let contentRegex: RegExp | null = null
    let highlightRegex: RegExp | null = null

    if (options.content) {
      if (isAdvancedQuery(options.content)) {
        parsedQuery = parseQuery(options.content)
        if (parsedQuery) {
          highlightRegex = buildHighlightPattern(parsedQuery)
        }
      } else {
        // Simple search - use as regex
        contentRegex = new RegExp(options.content, 'gi')
        highlightRegex = contentRegex
      }
    }

    const headingRegex = options.heading
      ? new RegExp(options.heading, 'i')
      : null

    const results: SearchResult[] = []

    // Group sections by document for efficient file reading
    const sectionsByDoc: Record<string, SectionEntry[]> = {}
    for (const section of Object.values(sectionIndex.sections)) {
      const docSections = sectionsByDoc[section.documentPath]
      if (docSections) {
        docSections.push(section)
      } else {
        sectionsByDoc[section.documentPath] = [section]
      }
    }

    // Process each document
    for (const [docPath, sections] of Object.entries(sectionsByDoc)) {
      // Apply path filter early
      if (options.pathPattern && !matchPath(docPath, options.pathPattern)) {
        continue
      }

      const document = docIndex.documents[docPath]
      if (!document) continue

      // Load file content for content search
      let fileContent: string | null = null
      let fileLines: string[] = []

      if (parsedQuery || contentRegex) {
        const filePath = path.join(storage.rootPath, docPath)
        try {
          fileContent = yield* Effect.promise(() =>
            fs.readFile(filePath, 'utf-8'),
          )
          fileLines = fileContent.split('\n')
        } catch {
          continue // Skip files that can't be read
        }
      }

      for (const section of sections) {
        // Apply heading filter
        if (headingRegex && !headingRegex.test(section.heading)) {
          continue
        }

        // Apply other filters
        if (
          options.hasCode !== undefined &&
          section.hasCode !== options.hasCode
        ) {
          continue
        }
        if (
          options.hasList !== undefined &&
          section.hasList !== options.hasList
        ) {
          continue
        }
        if (
          options.hasTable !== undefined &&
          section.hasTable !== options.hasTable
        ) {
          continue
        }
        if (
          options.minLevel !== undefined &&
          section.level < options.minLevel
        ) {
          continue
        }
        if (
          options.maxLevel !== undefined &&
          section.level > options.maxLevel
        ) {
          continue
        }

        // Content search
        if ((parsedQuery || contentRegex) && fileContent) {
          const sectionLines = fileLines.slice(
            section.startLine - 1,
            section.endLine,
          )
          const sectionContent = sectionLines.join('\n')

          // For boolean queries, evaluate against entire section content
          if (parsedQuery) {
            if (!evaluateQuery(parsedQuery.ast, sectionContent)) {
              continue // Section doesn't match query
            }
          }

          // Find individual line matches for highlighting
          const matches: ContentMatch[] = []
          const searchRegex = contentRegex || highlightRegex

          if (searchRegex) {
            for (let i = 0; i < sectionLines.length; i++) {
              const line = sectionLines[i]
              if (line && searchRegex.test(line)) {
                // Reset regex lastIndex for next test
                searchRegex.lastIndex = 0

                const absoluteLineNum = section.startLine + i

                // Create snippet with context (1 line before/after)
                const snippetStart = Math.max(0, i - 1)
                const snippetEnd = Math.min(sectionLines.length, i + 2)
                const snippetLines = sectionLines.slice(
                  snippetStart,
                  snippetEnd,
                )
                const snippet = snippetLines.join('\n')

                matches.push({
                  lineNumber: absoluteLineNum,
                  line: line,
                  snippet,
                })
              }
            }
          }

          // For boolean queries, include section even without line-level matches
          // (the section matched as a whole)
          if (parsedQuery || matches.length > 0) {
            const result: SearchResult = {
              section,
              document,
              sectionContent,
            }
            if (matches.length > 0) {
              results.push({ ...result, matches })
            } else {
              results.push(result)
            }

            if (
              options.limit !== undefined &&
              results.length >= options.limit
            ) {
              return results
            }
          }
        } else if (!parsedQuery && !contentRegex) {
          // No content search, heading-only search
          results.push({ section, document })

          if (options.limit !== undefined && results.length >= options.limit) {
            return results
          }
        }
      }
    }

    return results
  })

// ============================================================================
// Search with Content (legacy, uses heading-only search)
// ============================================================================

export const searchWithContent = (
  rootPath: string,
  options: SearchOptions = {},
): Effect.Effect<readonly SearchResult[], Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)
    const results = yield* search(rootPath, options)

    const resultsWithContent: SearchResult[] = []

    for (const result of results) {
      const filePath = path.join(storage.rootPath, result.section.documentPath)

      try {
        const fileContent = yield* Effect.promise(() =>
          fs.readFile(filePath, 'utf-8'),
        )

        const lines = fileContent.split('\n')
        const sectionContent = lines
          .slice(result.section.startLine - 1, result.section.endLine)
          .join('\n')

        resultsWithContent.push({
          ...result,
          sectionContent,
        })
      } catch {
        // If file can't be read, include result without content
        resultsWithContent.push(result)
      }
    }

    return resultsWithContent
  })

// ============================================================================
// Context Generation
// ============================================================================

export interface ContextOptions {
  /** Maximum tokens to include */
  readonly maxTokens?: number | undefined
  /** Include section content */
  readonly includeContent?: boolean | undefined
  /** Compression level: brief, summary, full */
  readonly level?: 'brief' | 'summary' | 'full' | undefined
}

export interface DocumentContext {
  readonly path: string
  readonly title: string
  readonly totalTokens: number
  readonly includedTokens: number
  readonly sections: readonly SectionContext[]
}

export interface SectionContext {
  readonly heading: string
  readonly level: number
  readonly tokens: number
  readonly content?: string | undefined
  readonly hasCode: boolean
  readonly hasList: boolean
  readonly hasTable: boolean
}

export const getContext = (
  rootPath: string,
  filePath: string,
  options: ContextOptions = {},
): Effect.Effect<DocumentContext, Error> =>
  Effect.gen(function* () {
    const storage = createStorage(rootPath)
    const resolvedFile = path.resolve(filePath)
    const relativePath = path.relative(storage.rootPath, resolvedFile)

    const docIndex = yield* loadDocumentIndex(storage)
    const sectionIndex = yield* loadSectionIndex(storage)

    if (!docIndex || !sectionIndex) {
      return yield* Effect.fail(
        new Error("Index not found. Run 'mdtldr index' first."),
      )
    }

    const document = docIndex.documents[relativePath]
    if (!document) {
      return yield* Effect.fail(
        new Error(`Document not found in index: ${relativePath}`),
      )
    }

    // Get sections for this document
    const sectionIds = sectionIndex.byDocument[document.id] ?? []
    const sections: SectionContext[] = []
    let includedTokens = 0
    const maxTokens = options.maxTokens ?? Infinity
    const includeContent = options.includeContent ?? options.level === 'full'

    // Read file content if needed
    let fileContent: string | null = null
    if (includeContent) {
      try {
        fileContent = yield* Effect.promise(() =>
          fs.readFile(resolvedFile, 'utf-8'),
        )
      } catch {
        // Continue without content
      }
    }

    const fileLines = fileContent?.split('\n') ?? []

    for (const sectionId of sectionIds) {
      const section = sectionIndex.sections[sectionId]
      if (!section) continue

      // Check token budget
      if (includedTokens + section.tokenCount > maxTokens) {
        // Include brief info only if we're over budget
        if (options.level === 'brief') continue

        sections.push({
          heading: section.heading,
          level: section.level,
          tokens: section.tokenCount,
          hasCode: section.hasCode,
          hasList: section.hasList,
          hasTable: section.hasTable,
        })
        continue
      }

      includedTokens += section.tokenCount

      let content: string | undefined
      if (includeContent && fileContent) {
        content = fileLines
          .slice(section.startLine - 1, section.endLine)
          .join('\n')
      }

      sections.push({
        heading: section.heading,
        level: section.level,
        tokens: section.tokenCount,
        content,
        hasCode: section.hasCode,
        hasList: section.hasList,
        hasTable: section.hasTable,
      })
    }

    return {
      path: relativePath,
      title: document.title,
      totalTokens: document.tokenCount,
      includedTokens,
      sections,
    }
  })

// ============================================================================
// LLM-Ready Output
// ============================================================================

export const formatContextForLLM = (context: DocumentContext): string => {
  const lines: string[] = []

  lines.push(`# ${context.title}`)
  lines.push(`Path: ${context.path}`)
  lines.push(`Tokens: ${context.includedTokens}/${context.totalTokens}`)
  lines.push('')

  for (const section of context.sections) {
    const prefix = '#'.repeat(section.level)
    const meta: string[] = []
    if (section.hasCode) meta.push('code')
    if (section.hasList) meta.push('list')
    if (section.hasTable) meta.push('table')

    const metaStr = meta.length > 0 ? ` [${meta.join(', ')}]` : ''
    lines.push(
      `${prefix} ${section.heading}${metaStr} (${section.tokens} tokens)`,
    )

    if (section.content) {
      lines.push('')
      lines.push(section.content)
      lines.push('')
    }
  }

  return lines.join('\n')
}

/**
 * Core data types for md-tldr
 * Based on DESIGN.md specifications
 */

// ============================================================================
// Document Types
// ============================================================================

export interface MdDocument {
  readonly id: string
  readonly path: string
  readonly title: string
  readonly frontmatter: Record<string, unknown>
  readonly sections: readonly MdSection[]
  readonly links: readonly MdLink[]
  readonly codeBlocks: readonly MdCodeBlock[]
  readonly metadata: DocumentMetadata
}

export interface DocumentMetadata {
  readonly wordCount: number
  readonly tokenCount: number
  readonly headingCount: number
  readonly linkCount: number
  readonly codeBlockCount: number
  readonly lastModified: Date
  readonly indexedAt: Date
}

// ============================================================================
// Section Types
// ============================================================================

export type HeadingLevel = 1 | 2 | 3 | 4 | 5 | 6

export interface MdSection {
  readonly id: string
  readonly heading: string
  readonly level: HeadingLevel
  readonly content: string
  readonly plainText: string
  readonly startLine: number
  readonly endLine: number
  readonly children: readonly MdSection[]
  readonly metadata: SectionMetadata
}

export interface SectionMetadata {
  readonly wordCount: number
  readonly tokenCount: number
  readonly hasCode: boolean
  readonly hasList: boolean
  readonly hasTable: boolean
}

// ============================================================================
// Link Types
// ============================================================================

export type LinkType = 'internal' | 'external' | 'image'

export interface MdLink {
  readonly type: LinkType
  readonly href: string
  readonly text: string
  readonly sectionId: string
  readonly line: number
}

// ============================================================================
// Code Block Types
// ============================================================================

export interface MdCodeBlock {
  readonly language: string | null
  readonly content: string
  readonly sectionId: string
  readonly startLine: number
  readonly endLine: number
}

// ============================================================================
// Error Types
// ============================================================================

export interface ParseError {
  readonly _tag: 'ParseError'
  readonly message: string
  readonly line?: number | undefined
  readonly column?: number | undefined
}

export interface IoError {
  readonly _tag: 'IoError'
  readonly message: string
  readonly path: string
  readonly cause?: unknown
}

export interface IndexError {
  readonly _tag: 'IndexError'
  readonly cause: 'DiskFull' | 'Permission' | 'Corrupted' | 'Unknown'
  readonly message: string
}

// ============================================================================
// Constructor Functions
// ============================================================================

export const ParseError = (
  message: string,
  line?: number,
  column?: number,
): ParseError => ({
  _tag: 'ParseError',
  message,
  line,
  column,
})

export const IoError = (
  message: string,
  path: string,
  cause?: unknown,
): IoError => ({
  _tag: 'IoError',
  message,
  path,
  cause,
})

export const IndexError = (
  cause: IndexError['cause'],
  message: string,
): IndexError => ({
  _tag: 'IndexError',
  cause,
  message,
})

/**
 * Markdown parser using remark/unified
 * Handles GFM (tables, task lists) and YAML frontmatter
 */

import * as crypto from 'node:crypto'
import { Effect } from 'effect'
import matter from 'gray-matter'
import type { Code, Heading, Image, Link, Parent, Root, Text } from 'mdast'
import remarkGfm from 'remark-gfm'
import remarkParse from 'remark-parse'
import { unified } from 'unified'
import { visit } from 'unist-util-visit'

import type {
  DocumentMetadata,
  HeadingLevel,
  MdCodeBlock,
  MdDocument,
  MdLink,
  MdSection,
  ParseError,
} from '../core/types.js'
import { countTokensApprox, countWords } from '../utils/tokens.js'

// ============================================================================
// Parser Configuration
// ============================================================================

const processor = unified().use(remarkParse).use(remarkGfm)

// ============================================================================
// Helper Functions
// ============================================================================

const generateId = (input: string): string => {
  return crypto.createHash('md5').update(input).digest('hex').slice(0, 12)
}

const slugify = (text: string): string => {
  return text
    .toLowerCase()
    .replace(/[^\w\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .trim()
}

const isInternalLink = (href: string): boolean => {
  if (href.startsWith('http://') || href.startsWith('https://')) return false
  if (href.startsWith('mailto:')) return false
  if (href.startsWith('#')) return true
  if (href.endsWith('.md') || href.includes('.md#')) return true
  return !href.includes('://')
}

const extractPlainText = (node: Parent | Root): string => {
  const texts: string[] = []
  visit(node, 'text', (textNode: Text) => {
    texts.push(textNode.value)
  })
  return texts.join(' ')
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const getNodeEndLine = (node: any): number => {
  return node?.position?.end?.line ?? 0
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const getNodeStartLine = (node: any): number => {
  return node?.position?.start?.line ?? 0
}

// ============================================================================
// Section Extraction
// ============================================================================

interface RawSection {
  heading: string
  level: HeadingLevel
  startLine: number
  endLine: number
  contentStartLine: number
  contentNodes: unknown[]
}

const extractRawSections = (tree: Root): RawSection[] => {
  const sections: RawSection[] = []
  const headings: {
    heading: string
    level: HeadingLevel
    line: number
    index: number
  }[] = []

  // First pass: collect all headings with their positions
  tree.children.forEach((node, index) => {
    if (node.type === 'heading') {
      const heading = node as Heading
      headings.push({
        heading: extractPlainText(heading),
        level: heading.depth as HeadingLevel,
        line: getNodeStartLine(node),
        index,
      })
    }
  })

  // Second pass: create sections from headings
  headings.forEach((h, i) => {
    const nextHeading = headings[i + 1]
    const endIndex = nextHeading ? nextHeading.index : tree.children.length

    // Get content nodes between this heading and the next
    const contentNodes = tree.children.slice(h.index + 1, endIndex)
    const lastContentNode = contentNodes[contentNodes.length - 1]
    const endLine = lastContentNode ? getNodeEndLine(lastContentNode) : h.line

    sections.push({
      heading: h.heading,
      level: h.level,
      startLine: h.line,
      endLine,
      contentStartLine: h.line + 1,
      contentNodes,
    })
  })

  return sections
}

const buildSectionHierarchy = (
  rawSections: RawSection[],
  docId: string,
  lines: string[],
): MdSection[] => {
  const result: MdSection[] = []
  const stack: { section: MdSection; level: number }[] = []

  for (const raw of rawSections) {
    const contentLines = lines.slice(raw.startLine - 1, raw.endLine)
    const content = contentLines.join('\n')
    const plainText = extractSectionPlainText(raw.contentNodes as Parent[])

    const hasCode = (raw.contentNodes as { type: string }[]).some(
      (n) => n.type === 'code',
    )
    const hasList = (raw.contentNodes as { type: string }[]).some(
      (n) => n.type === 'list',
    )
    const hasTable = (raw.contentNodes as { type: string }[]).some(
      (n) => n.type === 'table',
    )

    const section: MdSection = {
      id: `${docId}-${slugify(raw.heading)}`,
      heading: raw.heading,
      level: raw.level,
      content,
      plainText,
      startLine: raw.startLine,
      endLine: raw.endLine,
      children: [],
      metadata: {
        wordCount: countWords(plainText),
        tokenCount: countTokensApprox(content),
        hasCode,
        hasList,
        hasTable,
      },
    }

    // Build hierarchy: find parent for this section
    while (stack.length > 0 && stack[stack.length - 1]!.level >= raw.level) {
      stack.pop()
    }

    if (stack.length === 0) {
      result.push(section)
    } else {
      const parent = stack[stack.length - 1]!
      ;(parent.section.children as MdSection[]).push(section)
    }

    stack.push({ section, level: raw.level })
  }

  return result
}

const extractSectionPlainText = (nodes: Parent[]): string => {
  const texts: string[] = []
  for (const node of nodes) {
    if ('value' in node && typeof node.value === 'string') {
      texts.push(node.value)
    } else if ('children' in node) {
      texts.push(extractPlainText(node))
    }
  }
  return texts.join(' ')
}

const countAllSections = (sections: MdSection[]): number => {
  let count = 0
  for (const section of sections) {
    count += 1
    count += countAllSections(section.children as MdSection[])
  }
  return count
}

// ============================================================================
// Link Extraction
// ============================================================================

const extractLinks = (tree: Root, docId: string): MdLink[] => {
  const links: MdLink[] = []
  let currentSectionId = docId

  visit(tree, (node) => {
    if (node.type === 'heading') {
      currentSectionId = `${docId}-${slugify(extractPlainText(node as Heading))}`
    }

    if (node.type === 'link') {
      const link = node as Link
      const internal = isInternalLink(link.url)
      links.push({
        type: internal ? 'internal' : 'external',
        href: link.url,
        text: extractPlainText(link),
        sectionId: currentSectionId,
        line: getNodeStartLine(node),
      })
    }

    if (node.type === 'image') {
      const img = node as Image
      links.push({
        type: 'image',
        href: img.url,
        text: img.alt ?? '',
        sectionId: currentSectionId,
        line: getNodeStartLine(node),
      })
    }
  })

  return links
}

// ============================================================================
// Code Block Extraction
// ============================================================================

const extractCodeBlocks = (tree: Root, docId: string): MdCodeBlock[] => {
  const codeBlocks: MdCodeBlock[] = []
  let currentSectionId = docId

  visit(tree, (node) => {
    if (node.type === 'heading') {
      currentSectionId = `${docId}-${slugify(extractPlainText(node as Heading))}`
    }

    if (node.type === 'code') {
      const code = node as Code
      codeBlocks.push({
        language: code.lang ?? null,
        content: code.value,
        sectionId: currentSectionId,
        startLine: getNodeStartLine(node),
        endLine: getNodeEndLine(node),
      })
    }
  })

  return codeBlocks
}

// ============================================================================
// Main Parser Function
// ============================================================================

export interface ParseOptions {
  readonly path?: string
  readonly lastModified?: Date
}

export const parse = (
  content: string,
  options: ParseOptions = {},
): Effect.Effect<MdDocument, ParseError> =>
  Effect.gen(function* () {
    const path = options.path ?? 'unknown'
    const docId = generateId(path)
    const now = new Date()

    // Extract frontmatter (graceful handling for malformed YAML)
    let frontmatter: Record<string, unknown> = {}
    let markdownContent: string = content

    try {
      const parsed = matter(content)
      frontmatter = parsed.data
      markdownContent = parsed.content
    } catch (error) {
      // Malformed frontmatter - treat entire content as markdown
      const msg = error instanceof Error ? error.message : String(error)
      console.warn(
        `Warning: Malformed frontmatter in ${path}, skipping: ${msg.split('\n')[0]}`,
      )
    }

    // Parse markdown to AST
    const tree = processor.parse(markdownContent) as Root

    // Split content into lines for reference
    const lines = markdownContent.split('\n')

    // Extract sections
    const rawSections = extractRawSections(tree)
    const sections = buildSectionHierarchy(rawSections, docId, lines)

    // Extract links and code blocks
    const links = extractLinks(tree, docId)
    const codeBlocks = extractCodeBlocks(tree, docId)

    // Determine title (first H1 or filename)
    const firstH1 = sections.find((s) => s.level === 1)
    const title =
      firstH1?.heading ??
      (typeof frontmatter.title === 'string' ? frontmatter.title : null) ??
      path.split('/').pop()?.replace(/\.md$/, '') ??
      'Untitled'

    // Calculate metadata
    const totalContent = sections.map((s) => s.content).join('\n')
    const metadata: DocumentMetadata = {
      wordCount: countWords(totalContent),
      tokenCount: countTokensApprox(content),
      headingCount: countAllSections(sections),
      linkCount: links.length,
      codeBlockCount: codeBlocks.length,
      lastModified: options.lastModified ?? now,
      indexedAt: now,
    }

    const document: MdDocument = {
      id: docId,
      path,
      title,
      frontmatter,
      sections,
      links,
      codeBlocks,
      metadata,
    }

    return document
  })

/**
 * Parse a markdown file from the filesystem
 */
export const parseFile = (
  filePath: string,
): Effect.Effect<
  MdDocument,
  ParseError | { _tag: 'IoError'; message: string; path: string }
> =>
  Effect.gen(function* () {
    const fs = yield* Effect.promise(() => import('node:fs/promises'))

    let content: string
    let stats: Awaited<ReturnType<typeof fs.stat>>

    try {
      ;[content, stats] = yield* Effect.all([
        Effect.promise(() => fs.readFile(filePath, 'utf-8')),
        Effect.promise(() => fs.stat(filePath)),
      ])
    } catch (error) {
      return yield* Effect.fail({
        _tag: 'IoError' as const,
        message: error instanceof Error ? error.message : 'Unknown error',
        path: filePath,
      })
    }

    return yield* parse(content, {
      path: filePath,
      lastModified: stats.mtime,
    })
  })

