        sections: [
          {
            heading: 'Large L1',
            level: 2,
            originalTokens: 400,
            summaryTokens: 200,
            summary: 'Large level 1 content. '.repeat(40),
            children: [
              {
                heading: 'Large L2',
                level: 3,
                originalTokens: 200,
                summaryTokens: 100,
                summary: 'Large level 2 content. '.repeat(20),
                children: [
                  {
                    heading: 'Small L3',
                    level: 4,
                    originalTokens: 20,
                    summaryTokens: 10,
                    summary: 'Small.',
                    children: [],
                    hasCode: false,
                    hasList: false,
                    hasTable: false,
                  },
                ],
                hasCode: false,
                hasList: false,
                hasTable: false,
              },
            ],
            hasCode: false,
            hasList: false,
            hasTable: false,
          },
        ],
